export function resolveImage(key?: string | null): string {
  if (!key) return imageMap['placeholder'] || '/materials/placeholder.jpg';
  const k = String(key);
  if (imageMap[k]) return imageMap[k];
  const aliased = imageAliases[k];
  if (aliased && imageMap[aliased]) return imageMap[aliased];
  // common fallback: try lowercasing
  const lower = k.toLowerCase();
  if (imageMap[lower]) return imageMap[lower];
  const aliasedLower = imageAliases[lower];
  if (aliasedLower && imageMap[aliasedLower]) return imageMap[aliasedLower];
  return imageMap['placeholder'] || '/materials/placeholder.jpg';
}

